var o=[{slug:"getting-started-with-emotional-healing",id:1,title:"Getting Started with Emotional Healing",description:"A gentle introduction to beginning your healing journey with practical first steps.",icon:"Heart",category:"Foundation",relatedHub:"/start",relatedLabel:"Open Start Hub",body:["Emotional healing rarely follows a straight line. It starts with one honest moment of noticing — naming what you feel, without judging it.","If you are new here, the gentlest first step is to open the Start Hub. It offers small, low-pressure tools you can do in 60 seconds: a calming breath, a quick reframe, or a soft check-in with yourself.","There is no right pace. You are allowed to pause, to skip, and to come back another day. Healing is the practice of returning, again and again, with kindness."]},{slug:"understanding-your-nervous-system",id:2,title:"Understanding Your Nervous System",description:"Learn how your nervous system responds to stress and discover ways to find calm.",icon:"Shield",category:"Body-Mind",relatedHub:"/hubs/nervous-system",relatedLabel:"Visit the Nervous System Hub",body:["Your nervous system is always listening — to your environment, your thoughts, and the cues your body gives back. When it senses safety, it lets you rest. When it senses threat, it mobilises to protect you.","Understanding this system can soften self-blame. The reactions you may have wished away — racing heart, tight chest, foggy thinking — are protective responses, not personal failures.","The Nervous System Hub gathers gentle, body-based practices that help you cue safety: orienting, slow exhales, grounding through the senses. None of them require special skill or perfect conditions."]},{slug:"building-daily-wellness-habits",id:3,title:"Building Daily Wellness Habits",description:"Create sustainable routines that support your mental and emotional wellbeing.",icon:"Sparkles",category:"Daily Practice",relatedHub:"/start",relatedLabel:"Open the Daily Start Flow",body:["Sustainable wellness habits are the small, repeatable choices that quietly shape your day. They do not need to be impressive — they only need to be doable.","A useful starting point is to pick one tiny anchor: a single breath after waking, one mood check at lunch, or a short reflection before bed. The Start Hub stitches these together into a soft daily flow.","If you miss a day, that is part of the practice too. Begin again — without the inner lecture."]},{slug:"processing-difficult-emotions",id:4,title:"Processing Difficult Emotions",description:"Healthy strategies for working through challenging feelings with self-compassion.",icon:"Brain",category:"Emotional Work",relatedHub:"/hubs/journaling",relatedLabel:"Open the Journaling Hub",body:["Difficult emotions are messengers, not enemies. They often carry information about a need that has gone unmet, a value being crossed, or a boundary that wants to be drawn.","Writing slows the swirl. The Journaling Hub offers structured prompts that help you put feelings into words, name what is underneath, and choose one small next step — without forcing a tidy ending.","If a feeling becomes too big to hold alone, please reach out to someone you trust or use the Crisis Resources page. You do not have to do this in isolation."]},{slug:"developing-self-compassion",id:5,title:"Developing Self-Compassion",description:"Practical exercises to cultivate kindness and understanding toward yourself.",icon:"Heart",category:"Foundation",relatedHub:"/hubs/self-compassion",relatedLabel:"Visit the Self-Compassion Hub",body:["Self-compassion is not the same as letting yourself off the hook. It is the willingness to speak to yourself the way you would speak to someone you love when they are struggling.","Research suggests that self-compassion supports resilience, motivation, and emotional balance — often more reliably than self-criticism does.","The Self-Compassion Hub offers short, guided practices: a soothing hand-on-heart, a kind reframe, and a soft phrase you can return to when the inner critic gets loud."]},{slug:"creating-healthy-boundaries",id:6,title:"Creating Healthy Boundaries",description:"Learn to set and maintain boundaries that protect your emotional wellbeing.",icon:"Shield",category:"Relationships",relatedHub:"/hubs/boundaries",relatedLabel:"Visit the Boundaries Hub",body:["A boundary is a clear statement of what you will and will not do — for the sake of your wellbeing and the relationship.","Boundaries are not punishments. They are how you stay close to people without losing yourself.","The Boundaries Hub offers scripts, reflection prompts, and gentle ways to rehearse — so the next time you need to say less, more, or no, the words feel a little closer to hand."]}],a=[{slug:"the-science-of-self-compassion",id:1,title:"The Science of Self-Compassion",excerpt:"Research shows that self-compassion is linked to greater emotional resilience and wellbeing.",author:"Wellness Team",readTime:"5 min read",category:"Research",relatedHub:"/hubs/self-compassion",relatedLabel:"Practice Self-Compassion",body:["Self-compassion is the practice of meeting your own suffering with the same warmth you would offer a friend. Multiple studies link it to lower anxiety, lower shame, and steadier motivation over time.","It rests on three pillars: self-kindness instead of self-judgement, common humanity instead of isolation, and mindful awareness instead of over-identification with the feeling.","You can begin with one short practice: place a hand on your heart, breathe slowly, and offer yourself a single kind sentence — out loud, if it feels safe."]},{slug:"understanding-trauma-responses",id:2,title:"Understanding Trauma Responses",excerpt:"Learn about the different ways our bodies and minds respond to overwhelming experiences.",author:"Wellness Team",readTime:"8 min read",category:"Education",relatedHub:"/hubs/trauma-healing",relatedLabel:"Visit the Trauma-Healing Hub",body:["Trauma responses are protective. When something overwhelms our capacity to cope, the nervous system steps in with one of several patterns: fight, flight, freeze, or fawn.","These responses are not flaws or failures. They are evidence that something in you worked very hard to keep you safe.","Healing does not require reliving what happened. It often begins with restoring a sense of safety in the body — slowly, in small doses, with support. The Trauma-Healing Hub offers gentle, paced practices to begin that work."]},{slug:"the-power-of-mindful-breathing",id:3,title:"The Power of Mindful Breathing",excerpt:"Simple breathing techniques can activate your parasympathetic nervous system and reduce stress.",author:"Wellness Team",readTime:"4 min read",category:"Practical",relatedHub:"/hubs/breathwork",relatedLabel:"Try a Breathwork Practice",body:["Slow, intentional breathing is one of the few tools that directly speaks to the part of your nervous system that governs calm.","A simple pattern: breathe in for four counts, hold for four, exhale for four, hold for four. Repeat for a minute or two. The longer exhale is the part that does most of the soothing.","Visit the Breathwork Hub for a guided pacer that does the counting for you, plus a few alternate patterns to try."]},{slug:"building-emotional-resilience",id:4,title:"Building Emotional Resilience",excerpt:"Practical strategies for developing the ability to bounce back from life's challenges.",author:"Wellness Team",readTime:"6 min read",category:"Growth",relatedHub:"/hubs/nervous-system",relatedLabel:"Build Nervous-System Resilience",body:["Resilience is not the absence of pain. It is the capacity to recover, regroup, and re-engage after pain — sometimes in minutes, sometimes over months.","It grows from small, repeated experiences of feeling something hard and discovering you can metabolise it. Practices that calm the body, name the feeling, and reconnect you with what matters all build that capacity.","The Nervous System Hub is a good home base. Pair its short practices with one trusted relationship and one meaningful daily action — and resilience will quietly compound."]},{slug:"sleep-and-mental-health",id:5,title:"The Connection Between Sleep and Mental Health",excerpt:"How quality sleep supports emotional regulation and overall psychological wellbeing.",author:"Wellness Team",readTime:"7 min read",category:"Research",relatedHub:"/hubs/sleep",relatedLabel:"Visit the Sleep Hub",body:["Sleep is when your brain consolidates memory, processes emotion, and restocks its capacity to regulate. When sleep suffers, mood and patience usually follow.","Tiny anchors help: a wind-down routine, a stable wake time, low light in the last hour, and a brief mind-empty journal pass before bed.","The Sleep Hub gathers calming practices, soundscapes, and a structured wind-down so the path from awake to asleep feels less like a battle."]},{slug:"journaling-for-emotional-processing",id:6,title:"Journaling for Emotional Processing",excerpt:"Evidence-based benefits of expressive writing for mental health and emotional clarity.",author:"Wellness Team",readTime:"5 min read",category:"Practical",relatedHub:"/hubs/journaling",relatedLabel:"Open the Journaling Hub",body:["Expressive writing — putting feelings and experiences into words on a page — has been studied for decades and is consistently linked to improvements in mood, sleep, and even immune markers.","You do not need to be a writer. Spelling, grammar, and elegance do not matter. Honesty does.","The Journaling Hub offers structured prompts, free-write spaces, and a gentle archive so you can look back and notice the patterns that have been quietly shaping your weeks."]}];function s(e){return o.find(t=>t.slug===e)||null}function i(e){return a.find(t=>t.slug===e)||null}export{s as i,o as n,i as r,a as t};
